use Academorix\Observability\Activity\Concerns\LogsActivity;
use Spatie\Activitylog\LogOptions;

final class Booking extends Model
{
    use BelongsToTenant;   // ← must be first (tenancy hook)
    use LogsActivity;

    protected function getActivitylogOptions(): LogOptions
    {
        return LogOptions::defaults()
            ->logOnly(['facility_id', 'starts_at', 'ends_at', 'status'])
            ->logOnlyDirty()
            ->useLogName('bookings')
            ->setDescriptionForEvent(fn (string $event) => match ($event) {
                'created' => sprintf(
                    '%s booked %s for %s',
                    $this->causer?->display_name ?? 'Someone',
                    $this->facility->name,
                    $this->starts_at->format('D M j'),
                ),
                'updated' => sprintf(
                    '%s updated their booking on %s',
                    $this->causer?->display_name ?? 'Someone',
                    $this->facility->name,
                ),
                'deleted' => sprintf(
                    '%s cancelled their booking on %s',
                    $this->causer?->display_name ?? 'Someone',
                    $this->facility->name,
                ),
                default => 'Booking changed',
            });
    }
}
